+    /* Print first few events for illustration. */
+    for (uint32_t i = 0; i < count && i < 5; i++) {
+        if (asx_trace_event_get(i, &ev)) {
+            /*
+             * ERGO: asx_trace_event_kind_str() returns a human-readable
